class Solution {
public:
    string concatHex36(int n) {
        string hex = "";
        string hex36 = "";
        long long n2 = n * n;
        long long n3 = n * n * n;
        while (n2 > 0) {
            int remainder = n2 % 16;
            if (remainder < 10) {
                hex += to_string(remainder);
            } else {
                hex += char('A' + remainder - 10);
            }
            n2 /= 16;
        }
        reverse(hex.begin(), hex.end());
        while (n3 > 0) {
            int remainder = n3 % 36;
            if (remainder < 10) {
                hex36 += to_string(remainder);
            } else {
                hex36 += char('A' + remainder - 10);
            }
            n3 /= 36;
        }
        reverse(hex36.begin(), hex36.end());
        return hex + hex36;
    }
};
